/* Real-time E-commerce Frontend Logic */
const API_BASE = '';
const WS_PROTOCOL = location.protocol === 'https:' ? 'wss:' : 'ws:';
const WS_URL = `${WS_PROTOCOL}//${location.host}/ws/products`;
let products = [];

// DOM elements
const productsGrid = document.getElementById('products-grid');
const addForm = document.getElementById('add-product-form');
const loader = document.createElement('div');
loader.className = 'spinner';
loader.id = 'global-loader';
const errorDiv = document.createElement('div');
errorDiv.id = 'global-error';
errorDiv.style.cssText = 'position:fixed;top:1rem;right:1rem;background:#ef4444;color:#fff;padding:1rem;border-radius:8px;z-index:1000;display:none;';
document.body.appendChild(loader);
document.body.appendChild(errorDiv);

function showLoader(){ loader.style.display = 'block'; }
function hideLoader(){ loader.style.display = 'none'; }
function showError(msg){ errorDiv.textContent = msg; errorDiv.style.display = 'block'; setTimeout(()=>{ errorDiv.style.display = 'none'; }, 5000); }
function hideError(){ errorDiv.style.display = 'none'; }

// Fetch products
async function fetchProducts(){
 showLoader();
 hideError();
 try{
   const resp = await fetch(`${API_BASE}/api/products`);
   if(!resp.ok) throw new Error(`Failed to load products: ${resp.status}`);
   const data = await resp.json();
   products = data;
   renderProducts();
 }catch(err){
   showError(err.message);
 }finally{
   hideLoader();
 }
}

// Create product
async function createProduct(productData){
 showLoader();
 hideError();
 try{
   const resp = await fetch(`${API_BASE}/api/products`,{
     method:'POST',
     headers:{'Content-Type':'application/json'},
     body:JSON.stringify(productData)
   });
   if(!resp.ok) throw new Error('Create failed');
   const created = await resp.json();
   products.push(created);
   renderProducts();
   return created;
 }catch(err){
   showError(err.message);
 }finally{
   hideLoader();
 }
}

// Update product
async function updateProduct(id, updates){
 showLoader();
 hideError();
 try{
   const resp = await fetch(`${API_BASE}/api/products/${id}`,{
     method:'PATCH',
     headers:{'Content-Type':'application/json'},
     body:JSON.stringify(updates)
   });
   if(!resp.ok) throw new Error('Update failed');
   const updated = await resp.json();
   const idx = products.findIndex(p=>p.id===id);
   if(idx!==-1) products[idx]=updated;
   renderProducts();
   return updated;
 }catch(err){
   showError(err.message);
 }finally{
   hideLoader();
 }
}

// Delete product
async function deleteProduct(id){
 showLoader();
 hideError();
 try{
   const resp = await fetch(`${API_BASE}/api/products/${id}`,{method:'DELETE'});
   if(!resp.ok) throw new Error('Delete failed');
   products = products.filter(p=>p.id!==id);
   renderProducts();
 }catch(err){
   showError(err.message);
 }finally{
   hideLoader();
 }
}

// Render products grid
function renderProducts(){
 if(!productsGrid) return;
 productsGrid.innerHTML = '';
 if(products.length===0){
   const empty = document.createElement('p');
   empty.className='empty';
   empty.textContent='No products yet. Add one above!'
   productsGrid.appendChild(empty);
   return;
 }
 products.forEach(product=>{
   const card=document.createElement('div');
   card.className='product-card';
   card.innerHTML=
     `<img src="${product.imageUrl||'/placeholder.jpg'}" alt="${product.name}" class="product-img">
      <div class="product-content">
        <h3 class="product-title">${product.name}</h3>
        <p class="product-price">$${product.price.toFixed(2)}</p>
        <p class="product-desc">${product.description||''}</p>
        <div class="product-actions">
          <button class="btn btn-edit" data-id="${product.id}">Edit</button>
          <button class="btn btn-danger btn-delete" data-id="${product.id}">Delete</button>
        </div>
      </div>`;
   productsGrid.appendChild(card);
 });
 attachProductEvents();
}

// Attach event listeners to dynamically rendered buttons
function attachProductEvents(){
 document.querySelectorAll('.btn-edit').forEach(btn=>{
   btn.addEventListener('click',async e=>{
     const id=e.target.dataset.id;
     const product=products.find(p=>p.id==id);
     if(!product) return;
     const name=prompt('Edit product name:',product.name);
     const price=prompt('Edit product price:',product.price);
     const priceNum=parseFloat(price);
     if(name!==null && !isNaN(priceNum)){
       await updateProduct(id,{name,price:priceNum});
     }
   });
 });
 document.querySelectorAll('.btn-delete').forEach(btn=>{
   btn.addEventListener('click',async e=>{
     const id=e.target.dataset.id;
     if(confirm('Delete this product?')){
       await deleteProduct(id);
     }
   });
 });
}

// Handle add product form
if(addForm){
 addForm.addEventListener('submit',async e=>{
   e.preventDefault();
   const name=e.target.elements.name.value.trim();
   const price=parseFloat(e.target.elements.price.value);
   const description=e.target.elements.description.value.trim();
   const imageUrl=e.target.elements.imageUrl.value.trim()||'/placeholder.jpg';
   if(name && !isNaN(price)){
     await createProduct({name,price,description,imageUrl});
     e.target.reset();
   }else{
     showError('Please provide valid name and price.');
   }
 });
}

// Real-time WebSocket updates
const ws = new WebSocket(WS_URL);
ws.onopen=()=>{ console.log('WebSocket connected'); };
ws.onclose=()=>{ console.warn('WebSocket disconnected, attempting reconnect...'); setTimeout(()=>{ window.location.reload(); }, 3000); };
ws.onerror=err=>{ console.error('WebSocket error:', err); };
ws.onmessage=event=>{
  try{
    const data=JSON.parse(event.data);
    switch(data.type){
      case 'productCreated':
        products.push(data.product);
        renderProducts();
        break;
      case 'productUpdated':
        const idx=products.findIndex(p=>p.id===data.product.id);
        if(idx!==-1){ products[idx]=data.product; renderProducts(); }
        break;
      case 'productDeleted':
        products=products.filter(p=>p.id!==data.id);
        renderProducts();
        break;
    }
  }catch(e){
    console.error('Invalid WS message:', e);
  }
};

// Simple chart using Chart.js if available
function initSalesChart(){
   const ctx=document.getElementById('salesChart');
   if(!ctx) return;
   if(typeof Chart==='undefined'){
     console.warn('Chart.js not loaded, skipping chart init');
     return;
   }
   new Chart(ctx,{
     type:'line',
     data={
       labels:['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'],
       datasets:[{
         label:'Sales ($)',
         data:[1200,1900,1500,2500,2200,3000,2800,3500,3100,4000,3800,4500],
         borderColor:'var(--accent)',
         backgroundColor:'rgba(99,102,241,0.2)',
         tension:0.1,
         fill:true
       }]
     },
     options={
       responsive:true,
       maintainAspectRatio:false,
       plugins={
         legend:{ labels:{ color:'#fff' } },
         tooltip:{ backgroundColor:'rgba(0,0,0,0.7)' }
       },
       scales={
         x:{ ticks:{ color:'#fff' }, grid:{ color:'rgba(255,255,255,0.1)' } },
         y:{ ticks:{ color:'#fff' }, grid:{ color:'rgba(255,255,255,0.1)' } }
       }
     }
   });
}

// Initialize on DOMContentLoaded
document.addEventListener('DOMContentLoaded',()=>{
   fetchProducts();
   initSalesChart();
});
